package com.aadil.jobtracker.UserService;import com.aadil.jobtracker.entity.UserEntity;import com.aadil.jobtracker.UserRepository.UserRepository;import com.aadil.jobtracker.Validation.UserRequestDTO;import com.aadil.jobtracker.Validation.UserResponseDTO;import org.springframework.stereotype.Service;import java.util.List;import java.util.Optional;@Servicepublic class UserServiceImp implements UserService {    private final UserRepository userRepository;    public UserServiceImp(UserRepository userRepository) {        this.userRepository = userRepository;    }    public UserEntity mapToEntity (UserRequestDTO dto){        UserEntity user=new UserEntity();        user.setPassword(dto.getPassword());        user.setName(dto.getName());        user.setEmail(dto.getEmail());       return userRepository.save(user);    }    public UserResponseDTO mapToDTO (UserEntity user){        return new UserResponseDTO(user.getId(), user.getName(), user.getEmail());    }    @Override    public UserResponseDTO createUser(UserRequestDTO dto) {        if (userRepository.existsByName(dto.getName())){            throw new RuntimeException("User Name already exists");        }        if (userRepository.existsByEmail(dto.getEmail())){            throw new RuntimeException("User Email already exists");        }        UserEntity user=mapToEntity(dto);        UserEntity savedUsers=userRepository.save(user);        return mapToDTO(savedUsers);    }    @Override    public List<UserResponseDTO> createUsers(List<UserRequestDTO> dtos) {        List<UserEntity>users=dtos.stream().map(this::mapToEntity).toList();        List<UserEntity> savedUsers=userRepository.saveAll(users);        return savedUsers.stream().map(this::mapToDTO).toList();    }    @Override    public Optional<UserResponseDTO> getUser(Long id) {       return userRepository.findById(id).map(this::mapToDTO);    }    @Override    public List<UserResponseDTO> getUsersById(List<Long> ids) {        List<UserEntity> users=userRepository.findAllById(ids).stream().toList();        return users.stream().map(this::mapToDTO).toList();    }    @Override    public List<UserResponseDTO> getAllUsers(){       List<UserEntity> allUsers=userRepository.findAll();       return allUsers.stream().map(this::mapToDTO).toList();    }    @Override    public Optional<UserResponseDTO> updateUser(Long id, UserRequestDTO dto) {      return userRepository.findById(id).map(user -> {            user.setEmail(dto.getEmail());            user.setName(dto.getName());            user.setPassword(dto.getPassword());            UserEntity savedUser=userRepository.save(user);            return mapToDTO(savedUser);        });    }    @Override    public void deleteUser(Long id) {        userRepository.deleteById(id);    }    @Override    public void deleteAll() {        userRepository.deleteAll();    }    @Override    public void deleteById(List<Long> ids) {        userRepository.deleteAllById(ids);    }}